import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { createMint, getOrCreateAssociatedTokenAccount, mintTo } from '@solana/spl-token';

export default function DeployPage() {
  const { connection, wallets, addLog, setDeployedToken, addDebug } = useApp();
  const [tokenName, setTokenName] = useState('');
  const [tokenSymbol, setTokenSymbol] = useState('');
  const [decimals, setDecimals] = useState(9);
  const [isDeploying, setIsDeploying] = useState(false);
  const [selectedWallet, setSelectedWallet] = useState(0);

  const deployToken = async () => {
    addDebug('DEPLOY clicked');

    if (!connection || wallets.length === 0) {
      addLog('No connection or wallets', 'error');
      return;
    }

    const wallet = wallets[selectedWallet];
    addDebug('Wallet: ' + wallet.publicKey.slice(0,8));

    try {
      setIsDeploying(true);

      addDebug('Step 1: Create mint...');
      const mint = await createMint(
        connection,
        wallet.keypair,
        wallet.keypair.publicKey,
        wallet.keypair.publicKey,
        decimals
      );
      addDebug('Mint OK: ' + mint.toString().slice(0,8));

      addDebug('Step 2: Create account...');
      const tokenAccount = await getOrCreateAssociatedTokenAccount(
        connection,
        wallet.keypair,
        mint,
        wallet.keypair.publicKey
      );
      addDebug('Account OK');

      addDebug('Has address: ' + (tokenAccount && tokenAccount.address ? 'YES' : 'NO'));

      if (!tokenAccount || !tokenAccount.address) {
        addDebug('ERROR: No address!');
        throw new Error('Token account has no address');
      }

      addDebug('Address: ' + tokenAccount.address.toString().slice(0,10));

      const mintAmount = 1000;
      const amount = mintAmount * Math.pow(10, decimals);

      addDebug('Step 3: Mint ' + mintAmount + ' tokens...');

      try {
        addDebug('Calling mintTo...');
        await mintTo(
          connection,
          wallet.keypair,
          mint,
          tokenAccount.address,
          wallet.keypair.publicKey,
          amount
        );
        addDebug('Mint SUCCESS!');
      } catch (mintErr) {
        addDebug('Mint FAILED: ' + mintErr.message);
        throw mintErr;
      }

      const tokenInfo = {
        mint: mint.toString(),
        name: tokenName || 'My Token',
        symbol: tokenSymbol || 'MTK',
        decimals: decimals,
        supply: mintAmount,
        owner: wallet.publicKey,
        tokenAccount: tokenAccount.address.toString()
      };

      setDeployedToken(tokenInfo);
      addDebug('SUCCESS! Token deployed.');
      addLog('Token deployed!', 'success');

    } catch (err) {
      addDebug('ERROR: ' + err.message);
      console.error(err);
      addLog('Failed: ' + err.message, 'error');
    } finally {
      setIsDeploying(false);
    }
  };

  return (
    <div style={{ padding: '10px' }}>
      <div style={{ background: 'rgba(0,0,0,0.3)', padding: '15px', borderRadius: '8px' }}>
        <div style={{ color: '#00f3ff', marginBottom: '15px' }}>// DEPLOY TOKEN</div>

        {wallets.length === 0 ? (
          <p style={{ color: '#ff4444' }}>Create a wallet first!</p>
        ) : (
          <>
            <select value={selectedWallet} onChange={e => setSelectedWallet(Number(e.target.value))} style={{ width: '100%', marginBottom: '10px' }}>
              {wallets.map((w, i) => (
                <option key={w.publicKey} value={i}>{w.name} ({w.publicKey.slice(0,8)}...)</option>
              ))}
            </select>
            <input value={tokenName} onChange={e => setTokenName(e.target.value)} placeholder="Name" style={{ width: '100%', marginBottom: '10px' }} />
            <input value={tokenSymbol} onChange={e => setTokenSymbol(e.target.value)} placeholder="Symbol" style={{ width: '100%', marginBottom: '10px' }} />
            <input type="number" value={decimals} onChange={e => setDecimals(Number(e.target.value))} style={{ width: '100%', marginBottom: '10px' }} />
            <button onClick={deployToken} disabled={isDeploying} style={{ width: '100%', padding: '10px', background: isDeploying ? '#333' : '#00f3ff' }}>
              {isDeploying ? 'Deploying...' : 'Deploy'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}
